78: type QueryParams struct {
79: 	Limit     uint64
80: 	Offset    uint64 // deprecated
81: 	PageToken string
82: 	Order     Order // not exposed to the user yet
83: }
84: 
85: // Normalize adjusts query parameters within the enforced boundaries.
86: // For example, limit is adjusted to be in the range (0, max].
87: // Given the limit is not supplied (0) it is set to the default limit.
88: func (q *QueryParams) Normalize() {
89: 	if q.Limit == 0 {
90: 		q.Limit = DefaultListLimit
91: 	}
92: 
93: 	if q.Limit > MaxListLimit {
94: 		q.Limit = MaxListLimit
95: 	}
96: }
97: 
98: type QueryOption func(p *QueryParams)
99: 
100: func NewQueryParams(opts ...QueryOption) (params QueryParams) {
101: 	for _, opt := range opts {
102: 		opt(&params)
103: 	}
104: 
105: 	// NOTE(georgemac): I wanted to normalize under all circumstances
106: 	// However, for legacy reasons the core flag state APIs expect
107: 	// the default limit to be == 0. Normalize sets it to the default
108: 	// constant which is > 0.
109: 	// If we ever break this contract then we can normalize here.
110: 	// params.Normalize()
111: 
112: 	return params
113: }
114: 
115: func WithLimit(limit uint64) QueryOption {
116: 	return func(p *QueryParams) {
117: 		p.Limit = limit
118: 	}
119: }
120: 
121: func WithOffset(offset uint64) QueryOption {
122: 	return func(p *QueryParams) {
123: 		p.Offset = offset
124: 	}
125: }
126: 
127: func WithPageToken(pageToken string) QueryOption {
128: 	return func(p *QueryParams) {
129: 		p.PageToken = pageToken
130: 	}
131: }
132: 
133: type Order uint8
134: 
135: const (
136: 	OrderAsc Order = iota
137: 	OrderDesc
138: )
139: 
140: func (o Order) String() string {
141: 	switch o {
142: 	case OrderAsc:
143: 		return "ASC"
144: 	case OrderDesc:
145: 		return "DESC"
146: 	}
147: 	return ""
148: }
149: 
150: func WithOrder(order Order) QueryOption {
151: 	return func(p *QueryParams) {
152: 		p.Order = order
153: 	}
154: }
