186: // EvaluationStore returns data necessary for evaluation
187: type EvaluationStore interface {
188: 	// GetEvaluationRules returns rules applicable to flagKey provided
189: 	// Note: Rules MUST be returned in order by Rank
190: 	GetEvaluationRules(ctx context.Context, flag ResourceRequest) ([]*EvaluationRule, error)
191: 	GetEvaluationDistributions(ctx context.Context, rule IDRequest) ([]*EvaluationDistribution, error)
192: 	// GetEvaluationRollouts returns rollouts applicable to namespaceKey + flagKey provided
193: 	// Note: Rollouts MUST be returned in order by rank
194: 	GetEvaluationRollouts(ctx context.Context, flag ResourceRequest) ([]*EvaluationRollout, error)
195: }
